        = 
    callWithHandle {
    uniffiRustCallWithError(SshException) { _status ->
    UniffiLib.uniffi_isekai_terminal_core_fn_method_sshsession_connect(
        it,
        FfiConverterTypeSessionCallback.lower(`callback`),_status)
}
    }
    
    

